import { __decorate } from "tslib";
import { ChangeDetectionStrategy, Component, EventEmitter, Input, Output, ViewEncapsulation, } from '@angular/core';
import { LucideAngularModule, Check } from 'lucide-angular';
/**
 * Indicateur de progression d'un workflow (cf. décision F.3).
 * Read-only par défaut, opt-in `[clickable]="true"` pour permettre
 * le retour à une étape précédente complétée.
 */
let PfStepsComponent = class PfStepsComponent {
    constructor() {
        this.steps = [];
        this.current = 0;
        this.clickable = false;
        this.stepClick = new EventEmitter();
        this.CheckIcon = Check;
    }
    getStatus(index) {
        if (index < this.current)
            return 'completed';
        if (index === this.current)
            return 'current';
        return 'todo';
    }
    static { this.propDecorators = {
        steps: [{ type: Input }],
        current: [{ type: Input }],
        clickable: [{ type: Input }],
        stepClick: [{ type: Output }]
    }; }
};
