    Component({
        selector: 'pf-steps',
        standalone: true,
        imports: [LucideAngularModule],
        changeDetection: ChangeDetectionStrategy.OnPush,
        encapsulation: ViewEncapsulation.None,
        template: `
    <ol class="ds-steps">
      @for (step of steps; track $index; let i = $index; let last = $last) {
        @let status = getStatus(i);
        @let isClickable = clickable && status === 'completed';
        <li
          [class]="'ds-steps__item ds-steps__item--' + status"
          [attr.aria-current]="status === 'current' ? 'step' : null"
        >
          @if (isClickable) {
            <button
              type="button"
              class="ds-steps__button"
              [attr.aria-label]="'Revenir à l\\'étape ' + (i + 1)"
              (click)="stepClick.emit(i)"
            >
              <span class="ds-steps__marker" aria-hidden="true">
                @if (status === 'completed') {
                  <lucide-icon [img]="CheckIcon" [size]="16"></lucide-icon>
                } @else {
                  {{ i + 1 }}
                }
              </span>
              <span class="ds-steps__label">
                <span class="ds-steps__title">{{ step.title }}</span>
                @if (step.description) {
                  <span class="ds-steps__description">{{ step.description }}</span>
                }
              </span>
            </button>
          } @else {
            <span class="ds-steps__marker" aria-hidden="true">
              @if (status === 'completed') {
                <lucide-icon [img]="CheckIcon" [size]="16"></lucide-icon>
              } @else {
                {{ i + 1 }}
              }
            </span>
            <span class="ds-steps__label">
              <span class="ds-steps__title">{{ step.title }}</span>
              @if (step.description) {
                <span class="ds-steps__description">{{ step.description }}</span>
              }
            </span>
          }
        </li>
        @if (!last) {
          <li class="ds-steps__separator" aria-hidden="true"></li>
        }
      }
    </ol>
  `,
    })
], PfStepsComponent);
export { PfStepsComponent };
